VALUES
  ('elementary-0a2fc18c-moex-00503', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-112-55d283b0', 'sub-elementary-0a2fc18c-03', NULL, 'single_choice', '下列關於總統制之敘述，何者最明顯有誤？', '["總統與國會分別有獨立的民意基礎", "總統對於國會通過之法案有否決權", "國會對內閣沒有質詢的權力", "內閣成員同時具有國會議員身分"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:16+00:00", "source_pdf_sha1": "9565b8c6d34e", "answer_pdf_sha1": "411503a886ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "510", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00504', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-112-55d283b0', 'sub-elementary-0a2fc18c-03', NULL, 'single_choice', '有關民主，下列敘述何者錯誤？', '["公民投票是國民主權的展現，位階高於憲法", "在民主社會中，「保護少數」與「多數決」不可分離，而違憲審查是保護少數的一種制度設計", "民主政治的預設之一是主流意見會隨時代與環境而改變", "在普通、平等、直接、無記名的投票方法中，平等是指一人一票且票票等值"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:16+00:00", "source_pdf_sha1": "9565b8c6d34e", "answer_pdf_sha1": "411503a886ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "510", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00505', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-112-55d283b0', 'sub-elementary-0a2fc18c-03', NULL, 'single_choice', '下列何者不屬於「法律保留原則」之內涵？', '["行政行為或其他一切行政活動，均不得與法律相牴觸", "憲法要求特定事項須由立法機關以法律加以規定", "何種事項應以法律直接規範或得委由命令予以規定，視規範對象、內容或法益本身及其所受限制 之輕重而有不同", "有組織法之授權不等於即有作用法之授權"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:16+00:00", "source_pdf_sha1": "9565b8c6d34e", "answer_pdf_sha1": "411503a886ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "510", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00506', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-112-55d283b0', 'sub-elementary-0a2fc18c-03', NULL, 'single_choice', '關於聯邦國與單一國之選擇，下列敘述何者錯誤？', '["單一國之地方政府不具水平權力分立之機關", "兩者在國家統治權力分配上有所不同", "聯邦國之成員州或邦得有獨立之司法系統", "聯邦國之成員州或邦享有憲法保障之自主權"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:16+00:00", "source_pdf_sha1": "9565b8c6d34e", "answer_pdf_sha1": "411503a886ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "510", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00507', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-112-55d283b0', 'sub-elementary-0a2fc18c-03', NULL, 'single_choice', '依行政執行法規定，行政執行，應以適當之方法為之，不得逾達成執行目的之必要限度。此為下列 何原則之實現？', '["法律保留原則", "明確性原則", "信賴保護原則", "比例原則"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:16+00:00", "source_pdf_sha1": "9565b8c6d34e", "answer_pdf_sha1": "411503a886ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "510", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00508', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-112-55d283b0', 'sub-elementary-0a2fc18c-03', NULL, 'single_choice', '若交通監理機關依職權要求，換發行車執照前，須先繳清違規罰鍰，否則不得辦理。此可能涉及下 列何原則？', '["比例原則", "法律優位原則", "不當聯結禁止原則", "信賴保護原則"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:16+00:00", "source_pdf_sha1": "9565b8c6d34e", "answer_pdf_sha1": "411503a886ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "510", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00509', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-112-55d283b0', 'sub-elementary-0a2fc18c-03', NULL, 'single_choice', '行政機關為求裁量判斷標準一致，往往會以行政規則方式訂頒裁量基準。行政機關即應依該裁量基 準為行政行為，此為下列何種原則之表現？', '["行政自我拘束原則", "比例原則", "法律保留原則", "不當聯結禁止原則"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:16+00:00", "source_pdf_sha1": "9565b8c6d34e", "answer_pdf_sha1": "411503a886ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "510", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00510', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-112-55d283b0', 'sub-elementary-0a2fc18c-03', NULL, 'single_choice', '依司法院釋字第709號意旨，下列何者非該解釋所強調之都市更新應踐行的正當行政程序？', '["主管機關應將計畫相關資訊，對更新單元內申請人以外之其他土地及合法建築物所有權人分別為 送達", "應以公開方式舉辦聽證，使利害關係人得到場以言詞為意見之陳述及論辯", "應斟酌全部聽證紀錄，說明採納及不採納之理由作成核定", "在應舉辦聽證的前提下，利害關係人適時陳述意見與知悉相關資訊之機會即可省略之"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:16+00:00", "source_pdf_sha1": "9565b8c6d34e", "answer_pdf_sha1": "411503a886ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "510", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00511', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-112-55d283b0', 'sub-elementary-0a2fc18c-03', NULL, 'single_choice', '下列何者非屬行政秩序罰？', '["吊扣證照", "罰金", "沒入", "公布照片"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:16+00:00", "source_pdf_sha1": "9565b8c6d34e", "answer_pdf_sha1": "411503a886ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "510", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00512', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-112-55d283b0', 'sub-elementary-0a2fc18c-03', NULL, 'single_choice', '關於依行政罰法不予處罰之事由，下列敘述何者錯誤？', '["依法令之行為，不予處罰", "未滿18歲之未成年人之行為，不予處罰", "違反行政法上義務之行為非出於故意或過失者，不予處罰", "對於現在不法之侵害，而出於防衛自己或他人權利之行為，不予處罰"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:16+00:00", "source_pdf_sha1": "9565b8c6d34e", "answer_pdf_sha1": "411503a886ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "510", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL)
